import{_ as r,o as n,c as t,a0 as o}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse(`{"title":"Sousou no Frieren (Frieren: Beyond Journey's End)","description":"","frontmatter":{"type":"entity","title":"Sousou no Frieren (Frieren: Beyond Journey's End)","tags":["anime","manga","fantasy","drama","adventure"],"related":["frieren","himmel","heiter","eisen","long-lived-time-perception","post-adventure-narrative"],"sources":["anime/52991.md"],"created":"2026-07-10T00:00:00.000Z","updated":"2026-07-10T00:00:00.000Z","date":"2026-07-10T00:00:00.000Z"},"headers":[],"relativePath":"entities/sousou-no-frieren.md","filePath":"entities/sousou-no-frieren.md"}`),a={name:"entities/sousou-no-frieren.md"};function i(s,e,l,u,d,h){return n(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="sousou-no-frieren-frieren-beyond-journey-s-end" tabindex="-1">Sousou no Frieren (Frieren: Beyond Journey&#39;s End) <a class="header-anchor" href="#sousou-no-frieren-frieren-beyond-journey-s-end" aria-label="Permalink to &quot;Sousou no Frieren (Frieren: Beyond Journey&#39;s End)&quot;">​</a></h1><ul><li><strong>入库日期</strong>: 2026-07-10 《葬送的芙莉莲》是一部日本漫画及动画作品，由山田钟人原作、阿部司作画。动画版于2023年播出，共28集，在MyAnimeList上获得9.26的极高评分。</li></ul><h2 id="作品信息" tabindex="-1">作品信息 <a class="header-anchor" href="#作品信息" aria-label="Permalink to &quot;作品信息&quot;">​</a></h2><ul><li><strong>类型</strong>: 漫画（连载中）、动画（已完结，28集）</li><li><strong>动画首播</strong>: 2023年</li><li><strong>MAL评分</strong>: 9.26</li><li><strong>类型标签</strong>: Adventure, Award Winning, Drama, Fantasy</li></ul><h2 id="核心角色" tabindex="-1">核心角色 <a class="header-anchor" href="#核心角色" aria-label="Permalink to &quot;核心角色&quot;">​</a></h2><ul><li><strong><a href="/entities/frieren-芙莉莲.html">frieren</a></strong> — 精灵魔法使，本作主角，拥有逾千年的寿命</li><li><strong>辛美尔（Himmel）</strong> — 勇者，英雄队伍的领袖</li><li><strong>海塔（Heiter）</strong> — 僧侣，队伍中的治愈者</li><li><strong>艾泽（Eisen）</strong> — 矮人战士，队伍中的力量担当</li></ul><h2 id="叙事创新" tabindex="-1">叙事创新 <a class="header-anchor" href="#叙事创新" aria-label="Permalink to &quot;叙事创新&quot;">​</a></h2><p>作品以传统奇幻故事中&quot;击败魔王&quot;的终点作为起点，聚焦于英雄队伍解散后，长寿的精灵主角如何面对人类同伴的衰老与死亡。这种<a href="/concepts/冒险后的叙事-post-adventure-narrative.html">post-adventure-narrative</a>结构是其获得广泛好评的核心原因。</p><h2 id="主题" tabindex="-1">主题 <a class="header-anchor" href="#主题" aria-label="Permalink to &quot;主题&quot;">​</a></h2><p>作品深入探讨了<a href="/concepts/长寿种的时间感知-long-lived-time-perception.html">long-lived-time-perception</a>——时间尺度差异带来的情感鸿沟与认知冲突。记忆、失去、成长与重新理解&quot;短暂&quot;时光的价值是贯穿全剧的主题。</p><h2 id="影响力" tabindex="-1">影响力 <a class="header-anchor" href="#影响力" aria-label="Permalink to &quot;影响力&quot;">​</a></h2><p>9.26的MAL评分使其跻身该平台历史最高评分作品之列，反映了其在观众中的广泛认可。作品因其情感深度、叙事创新性和主题哲思而备受赞誉。</p>',12)])])}const p=r(a,[["render",i]]);export{m as __pageData,p as default};
